#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        char A[100], B[100];
        scanf("%d %s %d %s", &N, A, &M, B);
        int wordCounts[N * M];
        char words[N * M][3];
        for (int i = 0; i < N * M; i++) {
            scanf("%s %d", words[i], &wordCounts[i]);
        }
        // Greedy algorithm to construct sentences
        int sentenceCount = 0;
        int wordIndex = 0;
        while (wordIndex < N * M) {
            int sentenceWordCount = 0;
            char sentence[1000] = "";
            for (int i = wordIndex; i < N * M; i++) {
                if (wordCounts[i] > 0) {
                    strcat(sentence, words[i]);
                    strcat(sentence, " ");
                    wordCounts[i]--;
                    sentenceWordCount++;
                }
            }
            sentenceCount++;
            wordIndex += sentenceWordCount;
        }
        printf("%d\n", sentenceCount);
        // Output compressed article
        printf("%d\n", sentenceCount);
        for (int i = 0; i < sentenceCount; i++) {
            printf("1 %s\n", sentence);
        }
    }
    return 0;
}

