                int sentenceWordCount = 0;
                StringBuilder sentence = new StringBuilder();
                for (int i = wordIndex; i < N * M; i++) {
                    if (wordCounts[i] > 0) {
                        sentence.append(words[i]).append(" ");
                        wordCounts[i]--;
                        sentenceWordCount++;
