const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
while (T-- > 0) {
    const [N, A] = readline().split(' ');
    const [M, B] = readline().split(' ');
    const wordCounts = {};
    const words = {};
    for (let i = 0; i < N * M; i++) {
        const [word, count] = readline().split(' ');
        wordCounts[word] = parseInt(count);
        words[word] = 0;
    }
    // Greedy algorithm to construct sentences
    let sentenceCount = 0;
    let wordIndex = 0;
    const sentences = [];
    while (wordIndex < N * M) {
        let sentenceWordCount = 0;
        const sentence = [];
        for (const word in words) {
            if (wordCounts[word] > 0) {
                sentence.push(word);
                wordCounts[word]--;
                sentenceWordCount++;
            }
        }
        sentenceCount++;
        wordIndex += sentenceWordCount;
        sentences.push(sentence.join(' '));
    }
    console.log(sentenceCount);
    // Output compressed article
    console.log(sentences.length);
    for (const sentence of sentences) {
        console.log('1', sentence);
    }
}

